  1→import { wallOutline } from '@/geometry/wallGeometry';
  2→
  3→const HANDLE_SIZE = 8; // px, will use vectorEffect
  4→
  5→function WallSelection({ wall, zoom }) {
  6→  const outline = wallOutline(wall);
  7→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
  8→  const handleR = HANDLE_SIZE / zoom;
  9→
 10→  return (
 11→    <g>
 12→      <polygon
 13→        points={points}
 14→        fill="var(--color-selection-fill)"
 15→        stroke="var(--color-selection)"
 16→        strokeWidth={2}
 17→        strokeDasharray="6 3"
 18→        vectorEffect="non-scaling-stroke"
 19→      />
 20→      {/* Endpoint handles */}
 21→      <rect
 22→        data-handle="start"
 23→        x={wall.start.x - handleR / 2}
 24→        y={wall.start.y - handleR / 2}
 25→        width={handleR}
 26→        height={handleR}
 27→        fill="white"
 28→        stroke="var(--color-selection)"
 29→        strokeWidth={2}
 30→        vectorEffect="non-scaling-stroke"
 31→        style={{ cursor: 'move' }}
 32→      />
 33→      <rect
 34→        data-handle="end"
 35→        x={wall.end.x - handleR / 2}
 36→        y={wall.end.y - handleR / 2}
 37→        width={handleR}
 38→        height={handleR}
 39→        fill="white"
 40→        stroke="var(--color-selection)"
 41→        strokeWidth={2}
 42→        vectorEffect="non-scaling-stroke"
 43→        style={{ cursor: 'move' }}
 44→      />
 45→    </g>
 46→  );
 47→}
 48→
 49→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 50→  if (!selectedId || !floor) return null;
 51→
 52→  if (selectedType === 'wall') {
 53→    const wall = floor.walls.find(w => w.id === selectedId);
 54→    if (!wall) return null;
 55→    return <WallSelection wall={wall} zoom={zoom} />;
 56→  }
 57→
 58→  if (selectedType === 'door') {
 59→    const door = floor.doors.find(d => d.id === selectedId);
 60→    if (!door) return null;
 61→    const wall = floor.walls.find(w => w.id === door.wallId);
 62→    if (!wall) return null;
 63→    // Highlight parent wall subtly
 64→    const outline = wallOutline(wall);
 65→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 66→    return (
 67→      <polygon
 68→        points={points}
 69→        fill="none"
 70→        stroke="var(--color-selection)"
 71→        strokeWidth={2}
 72→        strokeDasharray="6 3"
 73→        vectorEffect="non-scaling-stroke"
 74→      />
 75→    );
 76→  }
 77→
 78→  if (selectedType === 'window') {
 79→    const win = floor.windows.find(w => w.id === selectedId);
 80→    if (!win) return null;
 81→    const wall = floor.walls.find(w => w.id === win.wallId);
 82→    if (!wall) return null;
 83→    const outline = wallOutline(wall);
 84→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 85→    return (
 86→      <polygon
 87→        points={points}
 88→        fill="none"
 89→        stroke="var(--color-selection)"
 90→        strokeWidth={2}
 91→        strokeDasharray="6 3"
 92→        vectorEffect="non-scaling-stroke"
 93→      />
 94→    );
 95→  }
 96→
 97→  if (selectedType === 'room') {
