 76→export function createInitialEditorState(activeFloorId) {
 77→  return {
 78→    activeTool: TOOLS.SELECT,
 79→    selectedId: null,
 80→    selectedType: null,
 81→    toolState: {},
 82→    viewport: { panX: 400, panY: 300, zoom: DEFAULT_ZOOM },
 83→    showGrid: true,
 84→    snapEnabled: true,
 85→    activeFloorId,
 86→  };
 87→}
