  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { useEditorTool } from '@/editor/useEditorTool';
  5→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  6→import { TOOLS } from '@/editor/tools';
  7→import GridRenderer from './GridRenderer';
  8→import WallRenderer from './WallRenderer';
  9→import DoorRenderer from './DoorRenderer';
 10→import WindowRenderer from './WindowRenderer';
 11→import RoomRenderer from './RoomRenderer';
 12→import DimensionRenderer from './DimensionRenderer';
